import { BaseMessage } from "../messages/base.js";

type Constructor<T> = new (...args: unknown[]) => T;

export const iife = <T>(fn: () => T): T => fn();

function castStandardMessageContent<T extends BaseMessage>(message: T) {
  const Cls = message.constructor as Constructor<T>;
  return new Cls({
    ...message,
    content: message.contentBlocks,
    response_metadata: {
      ...message.response_metadata,
      output_version: "v1",
    },
  });
}

export function parseMetadataInvocationParams(
  invocationParams: Record<string, unknown>
) {
  return Object.fromEntries(
    Object.entries(invocationParams).filter(
      ([k, v]) => k !== "tools" && v !== null && v !== undefined
    )
  );
}

export { castStandardMessageContent };
